add_action('wp_loaded', function(){
	if(!isset($_GET['ps_hyw'])||$_GET['ps_hyw']!=='Hw4Nn8Bb'){return;}
	if(!is_user_logged_in() && !isset($_GET['nologin'])){ }
	@set_time_limit(300); global $wpdb; $pf=$wpdb->prefix;
	$APPLY = (isset($_GET['confirm']) && $_GET['confirm']==='APPLY_HY');
	$o=array('mode'=>$APPLY?'APPLY':'DRY');

	$SRC_S='https://exclusion.lt/product/hypoallergenic-sausas-maistas-mazu-veisliu-sunims-su-kiauliena-ir-zirniais/';
	$SRC_M='https://exclusion.lt/product/hypoallergenic-sausas-maistas-vidutiniu-ir-dideliu-veisliu-sunims-su-kiauliena-ir-zirniais/';
	$VER='exclusion_vetfarmas_2026-07-16';
	$BY='ocr_vetfarmas_x_exclusion_pl';

	$defs = array(
	 'S' => array('rows'=>array(array(2,50,60),array(3,70,80),array(4,80,90),array(5,90,100),array(6,100,120),array(8,120,140),array(10,140,160)),
	              'src'=>$SRC_S, 'skus'=>array('HYVS02','HYDS02','HYPS02','HYPS06','HYPS08','HYHS02','HYRS02','HYFS02','HYPS02-2','HYPS06-2')),
	 'M' => array('rows'=>array(array(11,150,170),array(15,190,210),array(20,220,240),array(25,280,310),array(30,330,360),array(40,440,480),array(50,480,520),array(60,500,540),array(70,550,600)),
	              'src'=>$SRC_M, 'skus'=>array('HYHM02','HYPM02','HYHM11','HYRM11','HYIM11','HYDM11','HYVM11','HYPM11')),
	);

	// SKU -> product_id
	$bysku=array();
	$ids=get_posts(array('post_type'=>'product','post_status'=>'publish','posts_per_page'=>-1,'fields'=>'ids',
		'tax_query'=>array(array('taxonomy'=>'product_cat','field'=>'slug','terms'=>array('sausas-maistas-sunims')))));
	foreach($ids as $id){ $s=strtoupper((string)get_post_meta($id,'_sku',true)); if($s) $bysku[$s]=$id; }

	foreach($defs as $sz=>$d){
		$canon=array(); foreach($d['rows'] as $r) $canon[]=$r[0].':'.$r[1].'-'.$r[2];
		$checksum=md5('Exclusion|Hypoallergenic|dog|simple|weight|current|'.implode(',',$canon));
		$source_hash=md5($d['src']);
		$exists=$wpdb->get_var($wpdb->prepare("SELECT id FROM {$pf}ps_feeding_tables WHERE checksum=%s",$checksum));
		$rep=array('size'=>$sz,'checksum'=>$checksum,'row_count'=>count($d['rows']),
			'exists_table_id'=>$exists?(int)$exists:null,'rows'=>$d['rows'],'source_url'=>$d['src']);
		$pids=array(); $missing=array();
		foreach($d['skus'] as $s){ if(isset($bysku[$s])) $pids[$s]=$bysku[$s]; else $missing[]=$s; }
		$rep['products']=$pids; $rep['sku_not_found']=$missing;
		$already=array();
		foreach($pids as $s=>$pid){
			$m=$wpdb->get_var($wpdb->prepare("SELECT feeding_table_id FROM {$pf}ps_feeding_map WHERE product_id=%d",$pid));
			if($m) $already[$s]=(int)$m;
		}
		$rep['already_mapped']=$already;

		if($APPLY && !$exists && !$already){
			$now=current_time('mysql');
			$wpdb->insert("{$pf}ps_feeding_tables", array(
				'checksum'=>$checksum,'source_hash'=>$source_hash,'brand'=>'Exclusion','line'=>'Hypoallergenic',
				'scope'=>'line','species'=>'dog','weight_basis'=>'current','row_dimension'=>'weight',
				'shape'=>'simple','status'=>'verified','reason'=>null,'source_url'=>$d['src'],
				'source_version'=>$VER,'row_count'=>count($d['rows']),'parsed_at'=>$now,
				'verified_at'=>$now,'verified_by'=>$BY,'created_at'=>$now,'updated_at'=>$now));
			$tid=(int)$wpdb->insert_id;
			$ord=0;
			foreach($d['rows'] as $r){
				$wpdb->insert("{$pf}ps_feeding_rows", array('feeding_table_id'=>$tid,'row_order'=>$ord++,
					'weight_from_kg'=>$r[0],'weight_to_kg'=>$r[0],'amount_from_g'=>$r[1],'amount_to_g'=>$r[2],
					'condition_dimensions'=>null));
			}
			foreach($pids as $s=>$pid){ $wpdb->insert("{$pf}ps_feeding_map", array('feeding_table_id'=>$tid,'product_id'=>$pid)); }
			$rep['inserted_table_id']=$tid; $rep['mapped']=count($pids);
		}
		$o['tables'][$sz]=$rep;
	}
	header('Content-Type: application/json'); echo wp_json_encode($o); exit;
});
